diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 706cb828acc6..03b4b255142a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -4132,21 +4132,45 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
                                     m_Value(Ov)),
                        m_OneUse(m_ICmp(Pred, m_ExtractValue<0>(m_Deferred(WOV)),
                                        m_APInt(C2))))) &&
-      (WO->getBinaryOp() == Instruction::Add ||
-       WO->getBinaryOp() == Instruction::Sub) &&
-      (ICmpInst::isEquality(Pred) ||
-       WO->isSigned() == ICmpInst::isSigned(Pred)) &&
       match(WO->getRHS(), m_APInt(C1))) {
-    bool Overflow;
-    APInt NewC = WO->getBinaryOp() == Instruction::Add
-                     ? (ICmpInst::isSigned(Pred) ? C2->ssub_ov(*C1, Overflow)
-                                                 : C2->usub_ov(*C1, Overflow))
-                     : (ICmpInst::isSigned(Pred) ? C2->sadd_ov(*C1, Overflow)
-                                                 : C2->uadd_ov(*C1, Overflow));
-    if (!Overflow || ICmpInst::isEquality(Pred)) {
-      Value *NewCmp = Builder.CreateICmp(
-          Pred, WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
-      return BinaryOperator::CreateOr(Ov, NewCmp);
+    if (WO->getBinaryOp() == Instruction::Add ||
+        WO->getBinaryOp() == Instruction::Sub) {
+      // Existing handling for Add/Sub.
+      if (!(ICmpInst::isEquality(Pred) ||
+            WO->isSigned() == ICmpInst::isSigned(Pred)))
+        return nullptr; // Fall through to code after the if-block.
+      bool Overflow;
+      APInt NewC = WO->getBinaryOp() == Instruction::Add
+                       ? (ICmpInst::isSigned(Pred) ? C2->ssub_ov(*C1, Overflow)
+                                                   : C2->usub_ov(*C1, Overflow))
+                       : (ICmpInst::isSigned(Pred) ? C2->sadd_ov(*C1, Overflow)
+                                                   : C2->uadd_ov(*C1, Overflow));
+      if (!Overflow || ICmpInst::isEquality(Pred)) {
+        Value *NewCmp = Builder.CreateICmp(
+            Pred, WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
+        return BinaryOperator::CreateOr(Ov, NewCmp);
+      }
+    } else if (WO->getBinaryOp() == Instruction::Mul && !WO->isSigned() &&
+               !C1->isZero()) {
+      // For umul.with.overflow(X, C1):
+      // overflow || (product > C2)  -->  X > C2 / C1
+      // overflow || (product >= C2) -->  X > (C2-1) / C1  (when C2 > 0)
+      if (Pred == ICmpInst::ICMP_UGT) {
+        APInt NewC = C2->udiv(*C1);
+        Value *NewCmp = Builder.CreateICmpUGT(
+            WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
+        if (Ov->hasOneUse())
+          return replaceInstUsesWith(I, NewCmp);
+        return BinaryOperator::CreateOr(Ov, NewCmp);
+      }
+      if (Pred == ICmpInst::ICMP_UGE && !C2->isZero()) {
+        APInt NewC = (*C2 - 1).udiv(*C1);
+        Value *NewCmp = Builder.CreateICmpUGT(
+            WO->getLHS(), ConstantInt::get(WO->getLHS()->getType(), NewC));
+        if (Ov->hasOneUse())
+          return replaceInstUsesWith(I, NewCmp);
+        return BinaryOperator::CreateOr(Ov, NewCmp);
+      }
     }
   }

